package com.eafc26.discordstats.discord
import com.eafc26.discordstats.ea.model.PlayerEntry
/** * Selects the Xerife da Partida (best defensive player). * * ## Defensive Impact Score (DIS) * * DIS = tacklesMade × successRateFraction × timeWeight * * Where: * - successRateFraction = tacklesMade / tackleAttempts (0.0 – 1.0) * Continuously penalises sloppy tackling instead of a hard binary gate. * - timeWeight = min(secondsPlayed, FULL_MATCH_SECONDS) / FULL_MATCH_SECONDS * Normalises contribution to a full 90-minute match. * * ## Eligibility * - tackleAttempts >= 1 — must have engaged defensively. * - secondsPlayed >= [MIN_SECONDS_PLAYED] — at least 10 % of the match. * * Tiebreaker (equal DIS up to [SCORE_EPSILON]): higher successRate, then more tacklesMade. * * Disconnected or AI-replaced players are excluded via the eligibility filter * applied before calling this selector. */ object XerifeSelector {
/** Duration of a full 90-minute match in seconds. */ const val FULL_MATCH_SECONDS = 5400
/** * Minimum seconds played to be eligible (~10 % of 90 min). * Prevents a short substitute appearance from dominating the award. */ const val MIN_SECONDS_PLAYED = 540
/** Two DIS values closer than this are treated as equal for tiebreaking. */ private const val SCORE_EPSILON = 0.001
data class XerifeSelection( val player: PlayerEntry, val tacklesMade: Int, val tackleAttempts: Int, val successRate: Int, /** Defensive Impact Score used for ranking. */ val defensiveScore: Double, )
/** * Selects the Xerife from eligible outfield players. * Returns null if no player passes the eligibility criteria. */ fun select(outfield: Collection<PlayerEntry>): XerifeSelection? { data class Candidate( val player: PlayerEntry, val made: Int, val attempts: Int, val successRate: Int, val score: Double, )
val candidates = outfield.mapNotNull { player -> val attempts = player.tackleAttempts?.toIntOrNull() ?: return@mapNotNull null if (attempts <= 0) return@mapNotNull null
val seconds = player.secondsPlayed?.toIntOrNull() ?: 0 if (seconds < MIN_SECONDS_PLAYED) return@mapNotNull null
val made = player.tacklesMade?.toIntOrNull() ?: 0 val successRateFraction = made.toDouble() / attempts val timeWeight = minOf(seconds, FULL_MATCH_SECONDS).toDouble() / FULL_MATCH_SECONDS val score = made * successRateFraction * timeWeight
val successRateInt = (successRateFraction * 100).toInt()
Candidate(player, made, attempts, successRateInt, score) }
val best = candidates.maxWithOrNull( compareBy<Candidate> { it.score } .thenBy { it.successRate } .thenBy { it.made } ) ?: return null
return XerifeSelection( player = best.player, tacklesMade = best.made, tackleAttempts = best.attempts, successRate = best.successRate, defensiveScore = best.score, ) } }

package com.eafc26.discordstats.discord
import com.eafc26.discordstats.ea.model.PlayerEntry import kotlin.math.sqrt
/** * Selects the Xerife da Partida (best defensive player). * * ## Defensive Impact Score (DIS) * * DIS = tacklesMade × successRateFraction × timeWeight * * ### Components * * - **tacklesMade** — raw defensive volume. * * - **successRateFraction** = tacklesMade / tackleAttempts (0.0 – 1.0) * Multiplying by this fraction continuously penalises sloppy tackling without * an arbitrary binary gate: a 40 % tackler scores half what an 80 % tackler * produces at the same volume. * * - **timeWeight** = √(min(secondsPlayed, FULL_MATCH_SECONDS) / FULL_MATCH_SECONDS) * Square-root weighting applies diminishing returns to playing time, which * produces a fairer balance than a simple linear multiplier: * * | Minutes played | Linear weight | √ weight | * |----------------|--------------|----------| * | 90 (full game) | 1.00 | 1.00 | * | 45 (half) | 0.50 | 0.71 | * | 20 (late sub) | 0.22 | 0.47 | * | 10 | 0.11 | 0.33 | * * With a linear weight a substitute who played 20 minutes would need to be * ~4.5× as efficient as a full-game starter to beat them — which is * unrealistically demanding. The √ curve requires only ~2× improvement per * minute, which is both achievable and intuitively fair. * * ## Eligibility * - tackleAttempts >= 1 — must have engaged defensively at all. * - secondsPlayed >= [MIN_SECONDS_PLAYED] — at least ~10 % of the match * to prevent a single-minute appearance from competing for the award. * * ## Tiebreaker * Equal DIS → higher successRate → more tacklesMade. * * Disconnected or AI-replaced players are excluded via the eligibility filter * applied before calling this selector. */ object XerifeSelector {
/** Duration of a full 90-minute match in seconds. */ const val FULL_MATCH_SECONDS = 5400
/** * Minimum seconds played to be eligible (~10 % of 90 min ≈ 9 minutes). * Prevents a micro-substitute from competing for the award. */ const val MIN_SECONDS_PLAYED = 540
data class XerifeSelection( val player: PlayerEntry, val tacklesMade: Int, val tackleAttempts: Int, val successRate: Int, /** Defensive Impact Score used for ranking. Exposed for transparency / testing. */ val defensiveScore: Double, )
/** * Selects the Xerife from eligible outfield players. * Returns null if no player passes the eligibility criteria. */ fun select(outfield: Collection<PlayerEntry>): XerifeSelection? { data class Candidate( val player: PlayerEntry, val made: Int, val attempts: Int, val successRate: Int, val score: Double, )
val candidates = outfield.mapNotNull { player -> val attempts = player.tackleAttempts?.toIntOrNull() ?: return@mapNotNull null if (attempts <= 0) return@mapNotNull null
val seconds = player.secondsPlayed?.toIntOrNull() ?: 0 if (seconds < MIN_SECONDS_PLAYED) return@mapNotNull null
val made = player.tacklesMade?.toIntOrNull() ?: 0 val successRateFraction = made.toDouble() / attempts val timeRatio = minOf(seconds, FULL_MATCH_SECONDS).toDouble() / FULL_MATCH_SECONDS // √ weighting — diminishing returns on playing time (see KDoc for rationale) val timeWeight = sqrt(timeRatio) val score = made * successRateFraction * timeWeight
val successRateInt = (successRateFraction * 100).toInt()
Candidate(player, made, attempts, successRateInt, score) }
val best = candidates.maxWithOrNull( compareBy<Candidate> { it.score } .thenBy { it.successRate } .thenBy { it.made } ) ?: return null
return XerifeSelection( player = best.player, tacklesMade = best.made, tackleAttempts = best.attempts, successRate = best.successRate, defensiveScore = best.score, ) } }

package com.eafc26.discordstats.discord

import com.eafc26.discordstats.ea.model.PlayerEntry
import org.assertj.core.api.Assertions.assertThat
import org.assertj.core.api.Assertions.within
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class XerifeSelectorTest {

    // ------------------------------------------------------------------
    // Eligibility
    // ------------------------------------------------------------------

    @Nested
    inner class Eligibility {

        @Test
        fun `returns null for empty player list`() {
            assertThat(XerifeSelector.select(emptyList())).isNull()
        }

        @Test
        fun `returns null when no player attempted a tackle`() {
            val players = listOf(player("NoTackles", tackleAttempts = "0", tacklesMade = "0"))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `returns null when tackleAttempts is missing`() {
            val players = listOf(player("NoData", tackleAttempts = null, tacklesMade = null))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `returns null when player played less than MIN_SECONDS_PLAYED`() {
            // 539 seconds — just below the 10 % threshold
            val players = listOf(player("TooShort", tackleAttempts = "10", tacklesMade = "9", seconds = "539"))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `player at exactly MIN_SECONDS_PLAYED qualifies`() {
            val players = listOf(player("ExactMin", tackleAttempts = "5", tacklesMade = "4", seconds = "540"))
            assertThat(XerifeSelector.select(players)).isNotNull
        }

        @Test
        fun `player with all zero tackles (attempts=0) does not qualify even with long playing time`() {
            val players = listOf(player("ZeroAttempts", tackleAttempts = "0", tacklesMade = "0", seconds = "5400"))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `previously disqualifying 60 percent rate now qualifies under DIS`() {
            // Old rule: exactly 60% was disqualified. New rule: no rate threshold.
            val players = listOf(player("Sixty", tackleAttempts = "10", tacklesMade = "6"))
            assertThat(XerifeSelector.select(players)).isNotNull
            assertThat(XerifeSelector.select(players)!!.player.playerName).isEqualTo("Sixty")
        }

        @Test
        fun `low success rate (30 percent) still qualifies but scores low`() {
            val players = listOf(
                player("SloppyHighVolume", tackleAttempts = "20", tacklesMade = "6"),  // 30%
                player("EfficientLow",     tackleAttempts = "5",  tacklesMade = "4"),  // 80%
            )
            // EfficientLow: 4 × 0.8 × 1.0 = 3.2
            // SloppyHighVolume: 6 × 0.3 × 1.0 = 1.8
            val result = XerifeSelector.select(players)
            assertThat(result!!.player.playerName).isEqualTo("EfficientLow")
        }
    }

    // ------------------------------------------------------------------
    // DIS formula
    // ------------------------------------------------------------------

    @Nested
    inner class DefensiveImpactScore {

        @Test
        fun `score equals tacklesMade times successFraction times timeWeight`() {
            // 8 made / 10 attempts = 0.8 fraction, 5400s = 1.0 timeWeight
            // DIS = 8 × 0.8 × 1.0 = 6.4
            val players = listOf(player("A", tackleAttempts = "10", tacklesMade = "8", seconds = "5400"))
            val result = XerifeSelector.select(players)!!
            assertThat(result.defensiveScore).isCloseTo(6.4, within(0.001))
        }

        @Test
        fun `timeWeight caps at 1 for overtime seconds`() {
            // 6000s > 5400 — should be capped at 1.0
            val players = listOf(player("Extra", tackleAttempts = "5", tacklesMade = "5", seconds = "6000"))
            val result = XerifeSelector.select(players)!!
            // DIS = 5 × 1.0 × 1.0 = 5.0
            assertThat(result.defensiveScore).isCloseTo(5.0, within(0.001))
        }

        @Test
        fun `player with zero tacklesMade scores zero even with many attempts`() {
            val players = listOf(
                player("ZeroMade",  tackleAttempts = "10", tacklesMade = "0"),
                player("OneMade",   tackleAttempts = "1",  tacklesMade = "1"),
            )
            // ZeroMade DIS = 0 × 0 × 1.0 = 0
            // OneMade  DIS = 1 × 1.0 × 1.0 = 1.0
            val result = XerifeSelector.select(players)!!
            assertThat(result.player.playerName).isEqualTo("OneMade")
        }

        @Test
        fun `efficiency beats raw volume — 80pct with fewer tackles beats 40pct with more`() {
            // SloppyBig: 12 made / 30 att (40%), full game → DIS = 12 × 0.4 × 1.0 = 4.8
            // CleanSmall: 9 made / 11 att (81%), full game → DIS = 9 × 0.818 × 1.0 ≈ 7.36
            val players = listOf(
                player("SloppyBig",  tackleAttempts = "30", tacklesMade = "12"),
                player("CleanSmall", tackleAttempts = "11", tacklesMade = "9"),
            )
            val result = XerifeSelector.select(players)!!
            assertThat(result.player.playerName).isEqualTo("CleanSmall")
        }

        @Test
        fun `time weight penalises a short substitute despite high volume`() {
            // Sub: 8 made / 10 att (80%), 600s → DIS = 8 × 0.8 × (600/5400) ≈ 0.711
            // Starter: 5 made / 7 att (71%), 5400s → DIS = 5 × 0.714 × 1.0 ≈ 3.57
            val players = listOf(
                player("LateSub", tackleAttempts = "10", tacklesMade = "8", seconds = "600"),
                player("Starter", tackleAttempts = "7",  tacklesMade = "5", seconds = "5400"),
            )
            val result = XerifeSelector.select(players)!!
            assertThat(result.player.playerName).isEqualTo("Starter")
        }

        @Test
        fun `full-game player with more tackles wins over same rate but fewer tackles`() {
            // Both 80%, full game
            // MostTackles: 8 made / 10 att → DIS = 8 × 0.8 × 1.0 = 6.4
            // FewerTackles: 4 made / 5 att → DIS = 4 × 0.8 × 1.0 = 3.2
            val players = listOf(
                player("MostTackles",  tackleAttempts = "10", tacklesMade = "8"),
                player("FewerTackles", tackleAttempts = "5",  tacklesMade = "4"),
            )
            val result = XerifeSelector.select(players)!!
            assertThat(result.player.playerName).isEqualTo("MostTackles")
        }
    }

    // ------------------------------------------------------------------
    // Tiebreaking
    // ------------------------------------------------------------------

    @Nested
    inner class Tiebreaker {

        @Test
        fun `equal DIS breaks tie by higher success rate`() {
            // Both DIS ≈ 1.0 (designed to be equal), one has higher rate
            // A: 1 made / 1 att (100%) full game → DIS = 1.0
            // B: 2 made / 4 att (50%) full game  → DIS = 2 × 0.5 × 1.0 = 1.0  (same)
            val players = listOf(
                player("LowerRate",  tackleAttempts = "4", tacklesMade = "2"),   // 50%
                player("HigherRate", tackleAttempts = "1", tacklesMade = "1"),   // 100%
            )
            val result = XerifeSelector.select(players)!!
            assertThat(result.player.playerName).isEqualTo("HigherRate")
        }

        @Test
        fun `equal DIS and rate breaks tie by more tacklesMade`() {
            // Both 100% rate, 5400s; different volumes but same rate → same fraction, different made
            // A: 3 made / 3 att → DIS = 3 × 1.0 × 1.0 = 3.0
            // B: 2 made / 2 att → DIS = 2 × 1.0 × 1.0 = 2.0
            // Not a true tie in DIS, but tests thenBy fallback direction
            val players = listOf(
                player("More", tackleAttempts = "3", tacklesMade = "3"),
                player("Less", tackleAttempts = "2", tacklesMade = "2"),
            )
            val result = XerifeSelector.select(players)!!
            assertThat(result.player.playerName).isEqualTo("More")
        }
    }

    // ------------------------------------------------------------------
    // Selection result fields
    // ------------------------------------------------------------------

    @Nested
    inner class SelectionFields {

        @Test
        fun `selection exposes correct stats`() {
            val players = listOf(player("Xerife", tackleAttempts = "10", tacklesMade = "8", seconds = "5400"))
            val result = XerifeSelector.select(players)!!
            assertThat(result.tacklesMade).isEqualTo(8)
            assertThat(result.tackleAttempts).isEqualTo(10)
            assertThat(result.successRate).isEqualTo(80)
            assertThat(result.defensiveScore).isCloseTo(6.4, within(0.001))
        }
    }

    // ------------------------------------------------------------------
    // Helpers
    // ------------------------------------------------------------------

    private fun player(
        name: String,
        tackleAttempts: String? = null,
        tacklesMade: String? = null,
        seconds: String = "5400",
    ) = PlayerEntry(
        playerName = name,
        position = null,
        tackleAttempts = tackleAttempts,
        tacklesMade = tacklesMade,
        secondsPlayed = seconds,
    )
}

package com.eafc26.discordstats.discord

import com.eafc26.discordstats.ea.model.PlayerEntry
import org.assertj.core.api.Assertions.assertThat
import org.assertj.core.api.Assertions.within
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import kotlin.math.sqrt

/**
 * Tests for XerifeSelector.
 *
 * DIS = tacklesMade × (tacklesMade / tackleAttempts) × √(min(seconds, 5400) / 5400)
 */
class XerifeSelectorTest {

    // ── helpers ────────────────────────────────────────────────────────────────

    private fun player(
        name: String,
        tackleAttempts: String? = null,
        tacklesMade: String? = null,
        seconds: String = "5400",
    ) = PlayerEntry(
        playerName = name,
        position = null,
        tackleAttempts = tackleAttempts,
        tacklesMade = tacklesMade,
        secondsPlayed = seconds,
    )

    /** Expected DIS for known inputs — mirrors the formula exactly. */
    private fun dis(made: Int, attempts: Int, seconds: Int): Double {
        val fraction = made.toDouble() / attempts
        val timeWeight = sqrt(minOf(seconds, XerifeSelector.FULL_MATCH_SECONDS).toDouble() / XerifeSelector.FULL_MATCH_SECONDS)
        return made * fraction * timeWeight
    }

    // ── Eligibility ────────────────────────────────────────────────────────────

    @Nested
    inner class Eligibility {

        @Test
        fun `returns null for empty list`() {
            assertThat(XerifeSelector.select(emptyList())).isNull()
        }

        @Test
        fun `returns null when no player attempted a tackle`() {
            val players = listOf(player("None", tackleAttempts = "0", tacklesMade = "0"))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `returns null when tackleAttempts is missing`() {
            val players = listOf(player("NoData", tackleAttempts = null, tacklesMade = null))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `returns null when player played below MIN_SECONDS_PLAYED`() {
            // 539s — one second below the 9-minute threshold
            val players = listOf(player("TooShort", tackleAttempts = "10", tacklesMade = "9", seconds = "539"))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `player at exactly MIN_SECONDS_PLAYED qualifies`() {
            val players = listOf(player("ExactMin", tackleAttempts = "5", tacklesMade = "4", seconds = "540"))
            assertThat(XerifeSelector.select(players)).isNotNull
        }

        @Test
        fun `zero tackle attempts disqualifies even with full playing time`() {
            val players = listOf(player("Zero", tackleAttempts = "0", tacklesMade = "0", seconds = "5400"))
            assertThat(XerifeSelector.select(players)).isNull()
        }

        @Test
        fun `no binary rate threshold — 60 percent now qualifies`() {
            // The old implementation disqualified exactly 60 %. Under DIS there is no hard gate.
            val players = listOf(player("Sixty", tackleAttempts = "10", tacklesMade = "6"))
            val result = XerifeSelector.select(players)
            assertThat(result).isNotNull
            assertThat(result!!.player.playerName).isEqualTo("Sixty")
        }

        @Test
        fun `no binary rate threshold — 50 percent qualifies`() {
            val players = listOf(player("Fifty", tackleAttempts = "10", tacklesMade = "5"))
            assertThat(XerifeSelector.select(players)).isNotNull
        }
    }

    // ── DIS formula ────────────────────────────────────────────────────────────

    @Nested
    inner class Formula {

        @Test
        fun `score equals tacklesMade x successFraction x sqrtTimeWeight`() {
            // 8 made / 10 att = 0.8 fraction, 5400s → timeWeight = 1.0
            // DIS = 8 × 0.8 × 1.0 = 6.4
            val players = listOf(player("A", tackleAttempts = "10", tacklesMade = "8", seconds = "5400"))
            val result = XerifeSelector.select(players)!!
            assertThat(result.defensiveScore).isCloseTo(dis(8, 10, 5400), within(0.001))
        }

        @Test
        fun `timeWeight is capped at 1 for overtime seconds`() {
            // 6000s > 5400 — capped at 5400 before sqrt
            // DIS = 5 × 1.0 × √1.0 = 5.0
            val players = listOf(player("Extra", tackleAttempts = "5", tacklesMade = "5", seconds = "6000"))
            val result = XerifeSelector.select(players)!!
            assertThat(result.defensiveScore).isCloseTo(dis(5, 5, 5400), within(0.001))
        }

        @Test
        fun `timeWeight for half a match is sqrt of 0_5 not 0_5`() {
            // This test documents that sqrt gives 0.707, not the linear 0.5
            val players = listOf(player("Half", tackleAttempts = "4", tacklesMade = "4", seconds = "2700"))
            val result = XerifeSelector.select(players)!!
            val expectedWeight = sqrt(0.5)                  // ≈ 0.707 (not 0.5)
            val expectedScore = 4 * 1.0 * expectedWeight    // ≈ 2.828
            assertThat(result.defensiveScore).isCloseTo(expectedScore, within(0.001))
        }

        @Test
        fun `zero tacklesMade yields score of zero regardless of attempts`() {
            val players = listOf(
                player("ZeroMade", tackleAttempts = "10", tacklesMade = "0"),
                player("OneMade",  tackleAttempts = "1",  tacklesMade = "1"),
            )
            // ZeroMade DIS = 0; OneMade DIS = 1.0
            assertThat(XerifeSelector.select(players)!!.player.playerName).isEqualTo("OneMade")
        }
    }

    // ── Efficiency vs volume ───────────────────────────────────────────────────

    @Nested
    inner class EfficiencyVsVolume {

        @Test
        fun `efficient player beats high-volume sloppy player`() {
            // SloppyBig:  12 made / 30 att (40%), full game → DIS = 12 × 0.4  × 1.0 = 4.8
            // CleanSmall:  9 made / 11 att (81%), full game → DIS =  9 × 0.818 × 1.0 ≈ 7.36
            val players = listOf(
                player("SloppyBig",  tackleAttempts = "30", tacklesMade = "12"),
                player("CleanSmall", tackleAttempts = "11", tacklesMade = "9"),
            )
            assertThat(XerifeSelector.select(players)!!.player.playerName).isEqualTo("CleanSmall")
        }

        @Test
        fun `same rate but higher volume wins`() {
            // Both 80%; More wins by volume
            // DIS(More)   = 8 × 0.8 × 1.0 = 6.4
            // DIS(Fewer)  = 4 × 0.8 × 1.0 = 3.2
            val players = listOf(
                player("More",  tackleAttempts = "10", tacklesMade = "8"),
                player("Fewer", tackleAttempts = "5",  tacklesMade = "4"),
            )
            assertThat(XerifeSelector.select(players)!!.player.playerName).isEqualTo("More")
        }
    }

    // ── Time weighting (sqrt) ──────────────────────────────────────────────────

    @Nested
    inner class TimeWeighting {

        /**
         * With LINEAR weighting the starter would need only ~2× the sub's per-minute output
         * to beat them; with sqrt the bar drops to ~2× — but crucially the sub can still win
         * if they were genuinely ~2× more impactful.
         *
         * This test documents the "fair sub" scenario: an outstanding 20-min sub
         * should beat a mediocre full-game player.
         */
        @Test
        fun `outstanding late sub beats mediocre full-game player under sqrt weighting`() {
            // Sub:     6 made / 7 att (85.7%), 1200s → DIS ≈ 6 × 0.857 × √(1200/5400) ≈ 2.28
            // Starter: 4 made / 8 att (50.0%), 5400s → DIS = 4 × 0.50  × 1.0           = 2.0
            val sub     = player("OutstandingSub", tackleAttempts = "7", tacklesMade = "6", seconds = "1200")
            val starter = player("MediocreStarter", tackleAttempts = "8", tacklesMade = "4", seconds = "5400")
            val result = XerifeSelector.select(listOf(sub, starter))!!
            assertThat(result.player.playerName).isEqualTo("OutstandingSub")
            // Verify actual score is close to expected
            assertThat(result.defensiveScore).isCloseTo(dis(6, 7, 1200), within(0.001))
        }

        @Test
        fun `dominant full-game player beats short sub despite sub having high rate`() {
            // Starter: 10 made / 13 att (77%), 5400s → DIS = 10 × 0.769 × 1.0  ≈ 7.69
            // Sub:      8 made /  9 att (89%), 1000s → DIS =  8 × 0.889 × √(1000/5400) ≈ 3.05
            val starter = player("DominantStarter", tackleAttempts = "13", tacklesMade = "10", seconds = "5400")
            val sub     = player("EfficientSub",    tackleAttempts = "9",  tacklesMade = "8",  seconds = "1000")
            assertThat(XerifeSelector.select(listOf(starter, sub))!!.player.playerName)
                .isEqualTo("DominantStarter")
        }

        @Test
        fun `sqrt is more generous to partial-game players than linear would be`() {
            // At 2700s (half game): sqrt(0.5) ≈ 0.707, linear = 0.5
            // A player who played half the game gets 71 % credit, not 50 %
            val sqrtWeight = sqrt(2700.0 / 5400.0)
            assertThat(sqrtWeight).isGreaterThan(0.70)
            assertThat(sqrtWeight).isLessThan(0.72)
        }

        @Test
        fun `micro-sub below MIN_SECONDS_PLAYED is excluded even with perfect stats`() {
            // 539s → disqualified; even 5/5 (100%) should return null if alone
            val players = listOf(player("MicroSub", tackleAttempts = "5", tacklesMade = "5", seconds = "539"))
            assertThat(XerifeSelector.select(players)).isNull()
        }
    }

    // ── Tiebreakers ───────────────────────────────────────────────────────────

    @Nested
    inner class Tiebreaker {

        @Test
        fun `equal DIS breaks tie by higher success rate`() {
            // A: 2 made / 4 att (50%), 5400s → DIS = 2 × 0.5 × 1.0 = 1.0
            // B: 1 made / 1 att (100%), 5400s → DIS = 1 × 1.0 × 1.0 = 1.0  (tied)
            // B wins via successRate tiebreaker
            val players = listOf(
                player("LowerRate",  tackleAttempts = "4", tacklesMade = "2"),
                player("HigherRate", tackleAttempts = "1", tacklesMade = "1"),
            )
            assertThat(XerifeSelector.select(players)!!.player.playerName).isEqualTo("HigherRate")
        }

        @Test
        fun `equal DIS and rate breaks tie by more tacklesMade`() {
            // Both 100% rate, full game:
            // A: 3 made / 3 att → DIS = 3.0
            // B: 2 made / 2 att → DIS = 2.0  (not a true tie, but shows direction)
            val players = listOf(
                player("More", tackleAttempts = "3", tacklesMade = "3"),
                player("Less", tackleAttempts = "2", tacklesMade = "2"),
            )
            assertThat(XerifeSelector.select(players)!!.player.playerName).isEqualTo("More")
        }
    }

    // ── Selection result fields ───────────────────────────────────────────────

    @Nested
    inner class SelectionFields {

        @Test
        fun `exposed fields are correct`() {
            val players = listOf(player("Xerife", tackleAttempts = "10", tacklesMade = "8", seconds = "5400"))
            val result = XerifeSelector.select(players)!!
            assertThat(result.tacklesMade).isEqualTo(8)
            assertThat(result.tackleAttempts).isEqualTo(10)
            assertThat(result.successRate).isEqualTo(80)
            assertThat(result.defensiveScore).isCloseTo(dis(8, 10, 5400), within(0.001))
        }

        @Test
        fun `successRate is integer percentage (floor)`() {
            // 7 / 9 = 77.7…% → stored as 77
            val players = listOf(player("Partial", tackleAttempts = "9", tacklesMade = "7"))
            val result = XerifeSelector.select(players)!!
            assertThat(result.successRate).isEqualTo(77)
        }
    }
}
